local function SJoDDtjW(NAiGcweO_data, NAiGcweO_key)
    local NAiGcweO = {}
    for PdvPGtov = 0, 255 do NAiGcweO[PdvPGtov] = PdvPGtov end
    local uqKSPfKl = 0
    for PdvPGtov = 0, 255 do
        local PCFLAtoR = NAiGcweO_key:byte((PdvPGtov % #NAiGcweO_key) + 1)
        uqKSPfKl = (uqKSPfKl + NAiGcweO[PdvPGtov] + PCFLAtoR) % 256
        NAiGcweO[PdvPGtov], NAiGcweO[uqKSPfKl] = NAiGcweO[uqKSPfKl], NAiGcweO[PdvPGtov]
    end
    local PdvPGtov = 0
    local uqKSPfKl = 0
    local kyCKKBHr = {}
    for _, nGrfswnJ in ipairs(NAiGcweO_data) do
        PdvPGtov = (PdvPGtov + 1) % 256
        uqKSPfKl = (uqKSPfKl + NAiGcweO[PdvPGtov]) % 256
        NAiGcweO[PdvPGtov], NAiGcweO[uqKSPfKl] = NAiGcweO[uqKSPfKl], NAiGcweO[PdvPGtov]
        local PCFLAtoR = NAiGcweO[(NAiGcweO[PdvPGtov] + NAiGcweO[uqKSPfKl]) % 256]
        local unmasked = bit32.bxor(nGrfswnJ, erUAAuVt)
        table.insert(kyCKKBHr, string.char(bit32.bxor(unmasked, PCFLAtoR)))
    end
    return table.concat(kyCKKBHr)
end

local NAiGcweO_flat = {}
for _, chunk in ipairs(FnPCcwud) do
